  7→
  8→import { describe, it, before, after } from 'node:test';
  9→import assert from 'node:assert';
 10→import { projects } from './projects.js';
 11→import { prisma } from './prisma.js';
 12→
 13→const TEST = 't01-pj-';
 14→
 15→describe('ProjectRepository', { concurrency: false }, () => {
 16→  let userId: string;
 17→  let managerId: string;
 18→  let memberUserId: string;
 19→  let contactId: string;
 20→  let dealId: string;
 21→
 22→  before(async () => {
 23→    // Clean up leftover test data from previous runs
 24→    // Delete in reverse dependency order to respect foreign key constraints
 25→    // Use try-catch for cleanup to handle cases where data doesn't exist
 26→    try { await prisma.projectMember.deleteMany({ where: { projectId: { startsWith: TEST } } }); } catch {}
 27→    try { await prisma.projectStage.deleteMany({ where: { projectId: { startsWith: TEST } } }); } catch {}
 28→    try { await prisma.project.deleteMany({ where: { id: { startsWith: TEST } } }); } catch {}
 29→    try { await prisma.deal.deleteMany({ where: { id: { startsWith: TEST } } }); } catch {}
 30→    try { await prisma.dealStage.deleteMany({ where: { id: { startsWith: TEST } } }); } catch {}
 31→    try { await prisma.pipeline.deleteMany({ where: { id: { startsWith: TEST } } }); } catch {}
 32→    try { await prisma.contact.deleteMany({ where: { id: { startsWith: TEST } } }); } catch {}
 33→    // Users may be referenced by other entities, just try to delete
 34→    try { await prisma.user.deleteMany({ where: { id: { startsWith: TEST } } }); } catch {}
 35→
 36→    // Create test pipeline and stages for deals
 37→    const pipelineId = `${TEST}pipeline`;
 38→    await prisma.pipeline.create({
 39→      data: { id: pipelineId, code: `${TEST}default`, name: 'Test Pipeline', createdAt: new Date() },
 40→    });
 41→
 42→    const newStageId = `${TEST}new-stage`;
 43→    await prisma.dealStage.create({
 44→      data: { id: newStageId, code: `${TEST}new`, name: 'New', order: 1, probability: 10, pipelineId, color: '#888888' },
 45→    });
 46→
 47→    // Create test users
 48→    const now = new Date();
 49→    userId = `${TEST}user-a`;
 50→    managerId = `${TEST}user-b`;
